Here's a modern MSTest test class covering async patterns, timeouts, and cancellation:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    [Timeout(5000)] // Fails if test takes longer than 5s
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_OnNonSuccessStatusCode()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ThrowsOperationCanceled_WhenTokenCanceled()
    {
        var handler = new MockHttpMessageHandler("ok", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_RespectsCancellation_DuringRequest()
    {
        var handler = new MockHttpMessageHandler("ok", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Lightweight mock handler — no external mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Mechanism |
|---------|-----------|
| Async tests | Return `async Task` (never `async void`) |
| Timeouts | `[Timeout(ms)]` — MSTest cancels the test if exceeded |
| Pre-canceled token | `cts.Cancel()` before calling |
| Timeout-style cancel | `new CancellationTokenSource(TimeSpan)` |
| Exception assertions | `Assert.ThrowsExceptionAsync<T>` |
| HttpClient mocking | Custom `HttpMessageHandler` subclass — no third-party deps |

The `[Timeout]` attribute is your safety net against hanging tests in CI. It integrates with MSTest's internal `CancellationToken` propagation (available if you add a `CancellationToken` parameter to the test method in MSTest 3.x+).
